// src/components/SessionCollage.ts
var import_obsidian2 = require("obsidian");
function renderSessionCollage(container, app, settings, staggerIndex) {
  const card = container.createDiv({ cls: "olen-card olen-session-collage" });
  card.style.setProperty("--i", String(staggerIndex));
  card.createEl("div", { cls: "olen-heading", text: "RECENT SESSIONS" });
  const collageContainer = card.createDiv({ cls: "olen-collage-grid" });
  const recentSessions = getRecentSessions(app, settings, 5);
  if (recentSessions.length === 0) {
    collageContainer.createEl("div", {
      cls: "olen-body-italic",
      text: "No sessions yet. Begin your journey."
    });
    return;
  }
  for (let i = 0; i < recentSessions.length; i++) {
    const session = recentSessions[i];
    const sessionCard = collageContainer.createDiv({ cls: "olen-collage-card" });
    sessionCard.style.setProperty("--scatter", String(i));
    const accentColor = settings.categoryColors[session.category] ?? "#928d85";
    const accent = sessionCard.createDiv({ cls: "olen-collage-accent" });
    accent.style.background = accentColor;
    const info = sessionCard.createDiv({ cls: "olen-collage-info" });
    info.createEl("div", {
      cls: "olen-collage-emoji",
      text: session.emoji
    });
    info.createEl("div", {
      cls: "olen-collage-name",
      text: session.activityName
    });
    info.createEl("div", {
      cls: "olen-data-sm",
      text: session.date
    });
    if (session.type) {
      const typeBadge = info.createDiv({ cls: "olen-collage-type" });
      typeBadge.textContent = session.type;
    }
    if (session.duration) {
      info.createEl("div", {
        cls: "olen-data-sm",
        text: session.duration
      });
    }
  }
}
function getRecentSessions(app, settings, limit) {
  const sessions = [];
  const files = app.vault.getMarkdownFiles();
  for (const activity of settings.activities) {
    if (!activity.enabled)
      continue;
    const normalizedFolder = activity.folder.endsWith("/") ? activity.folder : activity.folder + "/";
    const activityFiles = files.filter(
      (f) => (f.path === activity.folder || f.path.startsWith(normalizedFolder)) && f.basename.startsWith("Workspace")
    );
    for (const file of activityFiles) {
      const cache = app.metadataCache.getFileCache(file);
      const fm = cache?.frontmatter;
      if (!fm)
        continue;
      sessions.push({
        activityName: activity.name,
        emoji: activity.emoji,
        category: activity.category,
        date: fm.Timestamp ? new Date(fm.Timestamp).toLocaleDateString("en-US", {
          month: "short",
          day: "numeric"
        }) : file.basename.replace("Workspace ", ""),
        type: fm[`${activity.property}-Type`],
        duration: fm.duration,
        filePath: file.path
      });
    }
  }
  sessions.sort((a, b) => {
    const fa = app.vault.getAbstractFileByPath(a.filePath);
    const fb = app.vault.getAbstractFileByPath(b.filePath);
    const ta = fa instanceof import_obsidian2.TFile ? fa.stat.mtime : 0;
    const tb = fb instanceof import_obsidian2.TFile ? fb.stat.mtime : 0;
    return tb - ta;
  });
  return sessions.slice(0, limit);
}

