function getLatestSession(app, activity) {
  const files = app.vault.getMarkdownFiles();
  const normalizedFolder = activity.folder.endsWith("/") ? activity.folder : activity.folder + "/";
  const sessionFiles = files.filter(
    (f) => (f.path === activity.folder || f.path.startsWith(normalizedFolder)) && f.basename.startsWith("Workspace")
  ).sort((a, b) => b.stat.mtime - a.stat.mtime);
  if (sessionFiles.length === 0)
    return null;
  const latest = sessionFiles[0];
  const cache = app.metadataCache.getFileCache(latest);
  const fm = cache?.frontmatter;
  let imagePath;
  if (cache?.embeds) {
    const imgEmbed = cache.embeds.find(
      (e) => /\.(png|jpg|jpeg|gif|webp|svg)$/i.test(e.link)
    );
    if (imgEmbed) {
      const imgFile = app.metadataCache.getFirstLinkpathDest(imgEmbed.link, latest.path);
      if (imgFile)
        imagePath = imgFile.path;
    }
  }
  return {
    date: fm?.Timestamp ? new Date(fm.Timestamp).toLocaleDateString("en-US", {
      weekday: "short",
      month: "short",
      day: "numeric"
    }) : latest.basename.replace("Workspace ", ""),
    duration: fm?.duration ?? "",
    type: fm?.[`${activity.property}-Type`] ?? "",
    skills: Array.isArray(fm?.skills) ? fm.skills : [],
    filePath: latest.path,
    imagePath
  };
}

// src/components/MomentumIndicator.ts
function renderMomentumIndicator(container, activity, completions, settings, staggerIndex) {
  const card = container.createDiv({ cls: "olen-momentum" });
  card.style.setProperty("--i", String(staggerIndex));
  const momentum = calculateMomentum(activity, completions, settings);
  const icon = momentum.state === "rising" ? "\u2191" : momentum.state === "falling" ? "\u2193" : "\u2192";
  const color = momentum.state === "rising" ? "var(--success)" : momentum.state === "falling" ? "var(--danger)" : "var(--text-muted)";
  const label = momentum.state === "rising" ? "Rising" : momentum.state === "falling" ? "Falling" : "Steady";
  card.createEl("span", {
    cls: "olen-momentum-icon",
    text: icon,
    attr: { style: `color: ${color}` }
  });
  card.createEl("span", {
    cls: "olen-momentum-label",
    text: label,
    attr: { style: `color: ${color}` }
  });
  card.createEl("span", {
    cls: "olen-data-sm",
    text: `${momentum.recentCount}/${momentum.avgCount} avg in 7d`
  });
}
function calculateMomentum(activity, completions, settings) {
  const now = settings.simulatedDate ? new Date(settings.simulatedDate) : /* @__PURE__ */ new Date();
  const activityCompletions = completions[activity.id] ?? [];
  const completedDates = new Set(
    activityCompletions.filter((c) => c.completed).map((c) => c.date)
  );
  let recentCount = 0;
  for (let i = 0; i < 7; i++) {
    const d = new Date(now);
    d.setDate(d.getDate() - i);
    const dateStr = d.toISOString().slice(0, 10);
    if (completedDates.has(dateStr))
      recentCount++;
  }
  let priorCount = 0;
  for (let i = 7; i < 14; i++) {
    const d = new Date(now);
    d.setDate(d.getDate() - i);
    const dateStr = d.toISOString().slice(0, 10);
    if (completedDates.has(dateStr))
      priorCount++;
  }
  const avgCount = Math.round((recentCount + priorCount) / 2 * 10) / 10;
  let state;
  if (recentCount > priorCount) {
    state = "rising";
  } else if (recentCount < priorCount) {
    state = "falling";
  } else {
    state = "steady";
  }
  return { state, recentCount, avgCount };
}

