function getSkillStats(app, activity) {
  const skillCounts = /* @__PURE__ */ new Map();
  const files = app.vault.getMarkdownFiles();
  const normalizedFolder = activity.folder.endsWith("/") ? activity.folder : activity.folder + "/";
  const now = /* @__PURE__ */ new Date();
  const twoWeeksAgo = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1e3).toISOString().slice(0, 10);
  for (const file of files) {
    if (!file.path.startsWith(normalizedFolder) && file.path !== activity.folder)
      continue;
    const cache = app.metadataCache.getFileCache(file);
    const fm = cache?.frontmatter;
    if (!fm || !Array.isArray(fm.skills))
      continue;
    const date = fm.Timestamp ? new Date(fm.Timestamp).toISOString().slice(0, 10) : file.basename;
    for (const skill of fm.skills) {
      const existing = skillCounts.get(skill);
      if (existing) {
        existing.count++;
        if (!existing.lastDate || date > existing.lastDate) {
          existing.lastDate = date;
        }
      } else {
        skillCounts.set(skill, { count: 1, lastDate: date });
      }
    }
  }
  if (activity.skillFolder) {
    const skillNormalizedFolder = activity.skillFolder.endsWith("/") ? activity.skillFolder : activity.skillFolder + "/";
    const skillFiles = files.filter((f) => f.path.startsWith(skillNormalizedFolder));
    for (const sf of skillFiles) {
      if (!skillCounts.has(sf.basename)) {
        skillCounts.set(sf.basename, { count: 0, lastDate: null });
      }
    }
  }
  const result = [];
  for (const [name, data] of skillCounts) {
    result.push({
      name,
      count: data.count,
      lastPracticed: data.lastDate,
      isNeglected: !data.lastDate || data.lastDate < twoWeeksAgo
    });
  }
  return result;
}

// src/components/PersonalRecords.ts
function renderPersonalRecords(container, app, activity, completions, settings, staggerIndex) {
  const card = container.createDiv({ cls: "olen-card olen-personal-records" });
  card.style.setProperty("--i", String(staggerIndex));
  card.createEl("div", { cls: "olen-heading", text: "PERSONAL RECORDS" });
  const records = calculateRecords(app, activity, completions);
  const grid = card.createDiv({ cls: "olen-records-grid" });
  const items = [
    { label: "Longest Streak", value: `${records.longestStreak} days`, icon: "\u{1F525}" },
    { label: "Best Week", value: `${records.bestWeekSessions} sessions`, icon: "\u{1F4CA}" },
    { label: "Discipline Wins", value: `${records.maxDisciplineStreak} in a row`, icon: "\u25C6" },
    { label: "Total Sessions", value: String(records.totalSessions), icon: "\u2299" }
  ];
  for (const item of items) {
    const el = grid.createDiv({ cls: "olen-record-item" });
    el.createEl("div", { cls: "olen-record-icon", text: item.icon });
    el.createEl("div", { cls: "olen-data", text: item.value });
    el.createEl("div", { cls: "olen-data-sm", text: item.label });
  }
}
function calculateRecords(app, activity, completions) {
  const activityCompletions = completions[activity.id] ?? [];
  const completedDates = activityCompletions.filter((c) => c.completed).map((c) => c.date).sort();
  const totalSessions = completedDates.length;
  let longestStreak = 0;
  let currentStreak = 0;
  let prevDate = null;
  for (const dateStr of completedDates) {
    const d = new Date(dateStr);
    if (prevDate) {
      const diffDays = Math.round(
        (d.getTime() - prevDate.getTime()) / (24 * 60 * 60 * 1e3)
      );
      if (diffDays === 1) {
        currentStreak++;
      } else {
        currentStreak = 1;
      }
    } else {
      currentStreak = 1;
    }
    longestStreak = Math.max(longestStreak, currentStreak);
    prevDate = d;
  }
  let bestWeekSessions = 0;
  if (completedDates.length > 0) {
    const dateSet = new Set(completedDates);
    const allDates = completedDates.map((d) => new Date(d));
    for (const startDate of allDates) {
      let weekCount = 0;
      for (let i = 0; i < 7; i++) {
        const checkDate = new Date(startDate);
        checkDate.setDate(checkDate.getDate() + i);
        const checkStr = checkDate.toISOString().slice(0, 10);
        if (dateSet.has(checkStr))
          weekCount++;
      }
      bestWeekSessions = Math.max(bestWeekSessions, weekCount);
    }
  }
  let maxDisciplineStreak = 0;
  let disciplineStreak = 0;
  const files = app.vault.getMarkdownFiles();
  const normalizedFolder = activity.folder.endsWith("/") ? activity.folder : activity.folder + "/";
  const sessionFiles = files.filter((f) => {
    if (!f.path.startsWith(normalizedFolder) && f.path !== activity.folder)
      return false;
    const cache = app.metadataCache.getFileCache(f);
    return cache?.frontmatter?.[activity.property] === true;
  }).sort((a, b) => a.stat.mtime - b.stat.mtime);
  for (const file of sessionFiles) {
    const cache = app.metadataCache.getFileCache(file);
    const type = cache?.frontmatter?.[`${activity.property}-Type`]?.toLowerCase();
    if (type === "discipline" || !type) {
      disciplineStreak++;
      maxDisciplineStreak = Math.max(maxDisciplineStreak, disciplineStreak);
    } else {
      disciplineStreak = 0;
    }
  }
  return {
    longestStreak,
    bestWeekSessions,
    maxDisciplineStreak,
    totalSessions
  };
}

