function getTracker(app) {
  const plugin = app.plugins?.plugins?.["track-habit-rank"] ?? app.plugins?.plugins?.["mythological-habit-tracker"];
  if (!plugin)
    return null;
  return {
    settings: plugin.settings,
    save: () => plugin.saveSettings?.() ?? plugin.saveData?.(plugin.settings),
    refresh: () => plugin.refreshRankView?.()
  };
}

